-- ============================================================
-- Insertar 30 clientes de prueba en Neon (PostgreSQL)
-- ============================================================
-- Calcula el próximo código CL-XXXX
DO $$
DECLARE
  cli_start INT;
  eq_start INT;
  ot_start INT;
  year_val TEXT;
BEGIN
  SELECT COALESCE(MAX(CAST(SUBSTRING(codigo, 4) AS INTEGER)), 0) + 1 INTO cli_start FROM clientes WHERE codigo LIKE 'CL-%';
  SELECT COALESCE(MAX(CAST(SUBSTRING(codigo, 4) AS INTEGER)), 0) + 1 INTO eq_start FROM equipos WHERE codigo LIKE 'EQ-%';
  year_val := EXTRACT(YEAR FROM NOW())::TEXT;
  SELECT COALESCE(MAX(CAST(SUBSTRING(numero_orden, 9) AS INTEGER)), 0) + 1 INTO ot_start FROM ordenes_trabajo WHERE numero_orden LIKE 'OT-' || year_val || '-%';

  -- Clientes
  ON CONFLICT (codigo) DO NOTHING;

  -- Equipos
  ON CONFLICT (codigo) DO NOTHING;

  -- Órdenes de Trabajo
  ON CONFLICT (numero_orden) DO NOTHING;

  RAISE NOTICE 'Insertados 30 clientes, 40 equipos, 40 OT';
END $$;
